def build(action_handlers):
    return TableLexer(TRANSITIONS, ACTIONS, action_handlers)

def start_state(rule_name):
    return RULES[rule_name]['start_state']

def interpret(rule_name, lexbuf):
    return build({}).interpret(start_state(rule_name), lexbuf)

def run(rule_name, lexbuf, action_handlers):
    action_id = interpret(rule_name, lexbuf)
    return action_handlers[rule_name][action_id](lexbuf)
